code.perVertex:
thresh = ((bass_att) > (thresh))*2+(1-((bass_att) > (thresh)))*((thresh-1.3)*0.96+1.3);;
dx_r = ((thresh) == (2))*0.015*sin(5*time)+(1-((thresh) == (2)))*dx_r;;
dy_r = ((thresh) == (2))*0.015*sin(6*time)+(1-((thresh) == (2)))*dy_r;;
crude = 2*abs(12*sin(rad-1/12*rad)*(4*rad));;
arc = cos(2*cos(1-abs(tan(2*rad-sin(12*rad)))));;
cinc = ((sin(bass_att)) > (1))*arc + ((sin(bass_att)) < (0.9))*crude;;
dx = dx + dx_r*cinc;;
dy = dy + dy_r*cinc;
